        nsmgr.AddNamespace("saml", "urn:oasis:names:tc:SAML:2.0:assertion");

        var authnRequest = doc.CreateElement("samlp", "AuthnRequest", "urn:oasis:names:tc:SAML:2.0:protocol");
        authnRequest.SetAttribute("ID", requestId);
        authnRequest.SetAttribute("Version", "2.0");
        authnRequest.SetAttribute("IssueInstant", XmlConvert.ToString(DateTime.UtcNow, XmlDateTimeSerializationMode.Utc));
        authnRequest.SetAttribute("Destination", destination);
        authnRequest.SetAttribute("AssertionConsumerServiceURL", acsUrl);
        authnRequest.SetAttribute("ProtocolBinding", "urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST");

        var issuerEl = doc.CreateElement("saml", "Issuer", "urn:oasis:names:tc:SAML:2.0:assertion");
        issuerEl.InnerText = issuer;

        var nameIdPolicy = doc.CreateElement("samlp", "NameIDPolicy", "urn:oasis:names:tc:SAML:2.0:protocol");
        nameIdPolicy.SetAttribute("Format", string.IsNullOrWhiteSpace(nameIdFormat) ? "urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified" : nameIdFormat);
        nameIdPolicy.SetAttribute("AllowCreate", "true");

        var requestedAuthnContext = doc.CreateElement("samlp", "RequestedAuthnContext", "urn:oasis:names:tc:SAML:2.0:protocol");
        requestedAuthnContext.SetAttribute("Comparison", "exact");

        var authnContextClassRef = doc.CreateElement("saml", "AuthnContextClassRef", "urn:oasis:names:tc:SAML:2.0:assertion");
        authnContextClassRef.InnerText = "urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport";

        requestedAuthnContext.AppendChild(authnContextClassRef);
        authnRequest.AppendChild(issuerEl);
        authnRequest.AppendChild(nameIdPolicy);
        authnRequest.AppendChild(requestedAuthnContext);

        doc.AppendChild(authnRequest);
        return doc;
    }
